mapper.select:
SELECT c.*, g.grade_name FROM sys_class c 
LEFT JOIN sys_grade g ON c.grade_id = g.grade_id 
WHERE c.class_id = #{classId}

mapper.update:
UPDATE sys_class SET class_name=#{className}, grade_id=#{gradeId}, 
    teacher_name=#{teacherName}, sort_order=#{sortOrder}, status=#{status} 
    WHERE class_id=#{classId}
